    /**
     * @method
     * @name timex#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://plasma-relay-backend.timex.io/swagger-ui/index.html?urls.primaryName=Relay#/Public/listCandles
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] timestamp in ms of the latest candle to fetch
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "market", Helpers.GetValue(market, "id") );
                put( "period", Timex.this.safeString(Timex.this.timeframes, timeframe, timeframe) );
            }};
            // if since and limit are not specified
            Object duration = this.parseTimeframe(timeframe);
            Object until = this.safeInteger(parameters, "until");
            if (Helpers.isTrue(Helpers.isEqual(limit, null)))
            {
                limit = 1000; // exchange provides tens of thousands of data, but we set generous default value
            }
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "from", this.iso8601(since));
                if (Helpers.isTrue(Helpers.isEqual(until, null)))
                {
                    Helpers.addElementToObject(request, "till", this.iso8601(this.sum(since, Helpers.multiply(Helpers.multiply(this.sum(limit, 1), duration), 1000))));
                } else
                {
                    Helpers.addElementToObject(request, "till", this.iso8601(until));
                }
            } else if (Helpers.isTrue(!Helpers.isEqual(until, null)))
            {
                Helpers.addElementToObject(request, "till", this.iso8601(until));
                Object fromTimestamp = Helpers.subtract(until, Helpers.multiply(Helpers.multiply(this.sum(limit, 1), duration), 1000));
                Helpers.addElementToObject(request, "from", this.iso8601(fromTimestamp));
            } else
            {
                Object now = this.milliseconds();
                Helpers.addElementToObject(request, "till", this.iso8601(now));
                Helpers.addElementToObject(request, "from", this.iso8601(Helpers.subtract(Helpers.subtract(now, Helpers.multiply(Helpers.multiply(this.sum(limit, 1), duration), 1000)), 1)));
            }
            parameters = this.omit(parameters, "until");
            Object response = (this.publicGetCandles(this.extend(request, parameters))).join();
            //
            //     [
            //         {
            //             "timestamp":"2019-12-04T23:00:00",
            //             "open":"0.02024009",
            //             "high":"0.02024009",
            //             "low":"0.02024009",
            //             "close":"0.02024009",
            //             "volume":"0.00008096036",
            //             "volumeQuote":"0.004",
            //         },
            //     ]
            //
            return this.parseOHLCVs(response, market, timeframe, since, limit);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

    public Object parseBalance(Object response)
    {
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
            put( "timestamp", null );
            put( "datetime", null );
        }};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(response)); i++)
        {
            Object balance = Helpers.GetValue(response, i);
            Object currencyId = this.safeString(balance, "currency");
            Object code = this.safeCurrencyCode(currencyId);
            Object account = this.account();
            Helpers.addElementToObject(account, "total", this.safeString(balance, "totalBalance"));
            Helpers.addElementToObject(account, "used", this.safeString(balance, "lockedBalance"));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

