    /**
     * @method
     * @name timex#createOrder
     * @description create a trade order
     * @see https://plasma-relay-backend.timex.io/swagger-ui/index.html?urls.primaryName=Relay#/Trading/createOrder
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object uppercaseSide = ((String)side).toUpperCase();
            Object uppercaseType = ((String)type).toUpperCase();
            Object postOnly = this.safeBool(parameters, "postOnly", false);
            if (Helpers.isTrue(postOnly))
            {
                uppercaseType = "POST_ONLY";
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("postOnly")));
            }
            final Object finalUppercaseType = uppercaseType;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "quantity", Timex.this.amountToPrecision(symbol, amount) );
                put( "side", uppercaseSide );
                put( "orderTypes", finalUppercaseType );
            }};
            Object query = parameters;
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(uppercaseType, "LIMIT"))) || Helpers.isTrue((Helpers.isEqual(uppercaseType, "POST_ONLY")))))
            {
                Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
                Object defaultExpireIn = this.safeInteger(this.options, "expireIn");
                Object expireTime = this.safeValue(parameters, "expireTime");
                Object expireIn = this.safeValue(parameters, "expireIn", defaultExpireIn);
                if (Helpers.isTrue(!Helpers.isEqual(expireTime, null)))
                {
                    Helpers.addElementToObject(request, "expireTime", expireTime);
                } else if (Helpers.isTrue(!Helpers.isEqual(expireIn, null)))
                {
                    Helpers.addElementToObject(request, "expireIn", expireIn);
                } else
                {
                    throw new InvalidOrder((String)Helpers.add(Helpers.add(Helpers.add(this.id, " createOrder() method requires a expireTime or expireIn param for a "), type), " order, you can also set the expireIn exchange-wide option")) ;
                }
                query = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("expireTime", "expireIn")));
            } else
            {
                Helpers.addElementToObject(request, "price", 0);
            }
            Object response = (this.tradingPostOrders(this.extend(request, query))).join();
            //
            //     {
            //         "orders": [
            //             {
            //                 "cancelledQuantity": "0.3",
            //                 "clientOrderId": "my-order-1",
            //                 "createdAt": "1970-01-01T00:00:00",
            //                 "cursorId": 50,
            //                 "expireTime": "1970-01-01T00:00:00",
            //                 "filledQuantity": "0.3",
            //                 "id": "string",
            //                 "price": "0.017",
            //                 "quantity": "0.3",
            //                 "side": "BUY",
            //                 "symbol": "TIMEETH",
            //                 "type": "LIMIT",
            //                 "updatedAt": "1970-01-01T00:00:00"
            //             }
            //         ]
            //     }
            //
            Object orders = this.safeValue(response, "orders", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object order = this.safeDict(orders, 0, new java.util.HashMap<String, Object>() {{}});
            return this.parseOrder(order, market);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

    public java.util.concurrent.CompletableFuture<Object> editOrder(Object id, Object symbol, Object type, Object side, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object amount = Helpers.getArg(optionalArgs, 0, null);
            Object price = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "id", id );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(amount, null)))
            {
                Helpers.addElementToObject(request, "quantity", this.amountToPrecision(symbol, amount));
            }
            if (Helpers.isTrue(!Helpers.isEqual(price, null)))
            {
                Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
            }
            Object response = (this.tradingPutOrders(this.extend(request, parameters))).join();
            //
            //     {
            //         "changedOrders": [
            //             {
            //                 "newOrder": {
            //                 "cancelledQuantity": "0.3",
            //                 "clientOrderId": "my-order-1",
            //                 "createdAt": "1970-01-01T00:00:00",
            //                 "cursorId": 50,
            //                 "expireTime": "1970-01-01T00:00:00",
            //                 "filledQuantity": "0.3",
            //                 "id": "string",
            //                 "price": "0.017",
            //                 "quantity": "0.3",
            //                 "side": "BUY",
            //                 "symbol": "TIMEETH",
            //                 "type": "LIMIT",
            //                 "updatedAt": "1970-01-01T00:00:00"
            //                 },
            //                 "oldId": "string",
            //             },
            //         ],
            //         "unchangedOrders": [ "string" ],
            //     }
            //
            if (Helpers.isTrue(Helpers.inOp(response, "unchangedOrders")))
            {
                Object orderIds = this.safeValue(response, "unchangedOrders", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                Object orderId = this.safeString(orderIds, 0);
                return this.safeOrder(new java.util.HashMap<String, Object>() {{
                    put( "id", orderId );
                    put( "info", response );
                }});
            }
            Object orders = this.safeValue(response, "changedOrders", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object firstOrder = this.safeValue(orders, 0, new java.util.HashMap<String, Object>() {{}});
            Object order = this.safeDict(firstOrder, "newOrder", new java.util.HashMap<String, Object>() {{}});
            return this.parseOrder(order, market);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

