    public Object parseMarket(Object market)
    {
        //
        //     {
        //         "symbol": "ETHBTC",
        //         "name": "ETH/BTC",
        //         "baseCurrency": "ETH",
        //         "baseTokenAddress": "0x45932db54b38af1f5a57136302eeba66a5975c15",
        //         "quoteCurrency": "BTC",
        //         "quoteTokenAddress": "0x8370fbc6ddec1e18b4e41e72ed943e238458487c",
        //         "feeCurrency": "BTC",
        //         "feeTokenAddress": "0x8370fbc6ddec1e18b4e41e72ed943e238458487c",
        //         "quantityIncrement": "0.0000001",
        //         "takerFee": "0.005",
        //         "makerFee": "0.0025",
        //         "tickSize": "0.00000001",
        //         "baseMinSize": "0.0001",
        //         "quoteMinSize": "0.00001",
        //         "locked": false
        //     }
        //
        Object locked = this.safeValue(market, "locked");
        Object id = this.safeString(market, "symbol");
        Object baseId = this.safeString(market, "baseCurrency");
        Object quoteId = this.safeString(market, "quoteCurrency");
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object amountIncrement = this.safeString(market, "quantityIncrement");
        Object minBase = this.safeString(market, "baseMinSize");
        Object minAmount = Precise.stringMax(amountIncrement, minBase);
        Object priceIncrement = this.safeString(market, "tickSize");
        Object minCost = this.safeNumber(market, "quoteMinSize");
        return new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "symbol", Helpers.add(Helpers.add(base, "/"), quote) );
            put( "base", base );
            put( "quote", quote );
            put( "settle", null );
            put( "baseId", baseId );
            put( "quoteId", quoteId );
            put( "settleId", null );
            put( "type", "spot" );
            put( "spot", true );
            put( "margin", false );
            put( "swap", false );
            put( "future", false );
            put( "option", false );
            put( "active", !Helpers.isTrue(locked) );
            put( "contract", false );
            put( "linear", null );
            put( "inverse", null );
            put( "taker", Timex.this.safeNumber(market, "takerFee") );
            put( "maker", Timex.this.safeNumber(market, "makerFee") );
            put( "contractSize", null );
            put( "expiry", null );
            put( "expiryDatetime", null );
            put( "strike", null );
            put( "optionType", null );
            put( "precision", new java.util.HashMap<String, Object>() {{
                put( "amount", Timex.this.safeNumber(market, "quantityIncrement") );
                put( "price", Timex.this.safeNumber(market, "tickSize") );
            }} );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "leverage", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", Timex.this.parseNumber(minAmount) );
                    put( "max", null );
                }} );
                put( "price", new java.util.HashMap<String, Object>() {{
                    put( "min", Timex.this.parseNumber(priceIncrement) );
                    put( "max", null );
                }} );
                put( "cost", new java.util.HashMap<String, Object>() {{
                    put( "min", minCost );
                    put( "max", null );
                }} );
            }} );
            put( "created", null );
            put( "info", market );
        }};
    }

    public Object parseCurrency(Object currency)
    {
        //
        //     {
        //         "symbol": "BTC",
        //         "name": "Bitcoin",
        //         "address": "0x8370fbc6ddec1e18b4e41e72ed943e238458487c",
        //         "icon": "data:image/svg+xml;base64,PHN2ZyB3aWR...mc+Cg==",
        //         "background": "transparent",
        //         "fiatSymbol": "BTC",
        //         "decimals": 8,
        //         "tradeDecimals": 20,
        //         "displayDecimals": 4,
        //         "crypto": true,
        //         "depositEnabled": true,
        //         "withdrawalEnabled": true,
        //         "transferEnabled": true,
        //         "buyEnabled": false,
        //         "purchaseEnabled": false,
        //         "redeemEnabled": false,
        //         "active": true,
        //         "withdrawalFee": "50000000000000000",
        //         "purchaseCommissions": []
        //     }
        //
        // https://github.com/ccxt/ccxt/issues/6878
        //
        //     {
        //         "symbol":"XRP",
        //         "name":"Ripple",
        //         "address":"0x0dc8882914f3ddeebf4cec6dc20edb99df3def6c",
        //         "decimals":6,
        //         "tradeDecimals":16,
        //         "depositEnabled":true,
        //         "withdrawalEnabled":true,
        //         "transferEnabled":true,
        //         "active":true
        //     }
        //
        Object id = this.safeString(currency, "symbol");
        Object code = this.safeCurrencyCode(id);
        // const fee = this.safeNumber (currency, 'withdrawalFee');
        Object feeString = this.safeString(currency, "withdrawalFee");
        Object tradeDecimals = this.safeInteger(currency, "tradeDecimals");
        Object fee = null;
        if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(feeString, null))) && Helpers.isTrue((!Helpers.isEqual(tradeDecimals, null)))))
        {
            Object feeStringLen = ((String)feeString).length();
            Object dotIndex = Helpers.subtract(feeStringLen, tradeDecimals);
            if (Helpers.isTrue(Helpers.isGreaterThan(dotIndex, 0)))
            {
                Object whole = Helpers.slice(feeString, 0, dotIndex);
                Object fraction = Helpers.slice(feeString, Helpers.opNeg(dotIndex), null);
                fee = this.parseNumber(Helpers.add(Helpers.add(whole, "."), fraction));
            } else
            {
                Object fraction = ".";
                for (var i = 0; Helpers.isLessThan(i, Helpers.opNeg(dotIndex)); i++)
                {
                    fraction = Helpers.add(fraction, "0");
                }
                fee = this.parseNumber(Helpers.add(fraction, feeString));
            }
        }
        final Object finalFee = fee;
        return this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
            put( "id", code );
            put( "code", code );
            put( "info", currency );
            put( "type", null );
            put( "name", Timex.this.safeString(currency, "name") );
            put( "active", Timex.this.safeBool(currency, "active") );
            put( "deposit", Timex.this.safeBool(currency, "depositEnabled") );
            put( "withdraw", Timex.this.safeBool(currency, "withdrawalEnabled") );
            put( "fee", finalFee );
            put( "precision", Timex.this.parseNumber(Timex.this.parsePrecision(Timex.this.safeString(currency, "decimals"))) );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "withdraw", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "networks", new java.util.HashMap<String, Object>() {{}} );
        }});
    }

